//  ГѓвЂљNGULOS Гўв‚¬вЂќ Transferidor 360Г‚В° com ponteiro arrastГѓВЎvel + modelo 3D
//  0Г‚В° = baixo, 90Г‚В° = direita, 180Г‚В° = cima, 270Г‚В° = esquerda
// ГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђ

let currentAngulo = 0;
let _angDragging  = false;

const TERMINAL_IMG = new Image();
TERMINAL_IMG.src   = 'data:image/png;base64,';

function renderAngulos() {
  _angDrawAll();
  updateRangeTrack(0);
}

// ГўвЂќв‚¬ГўвЂќв‚¬ Range slider ГўвЂќв‚¬ГўвЂќв‚¬
function updateRangeTrack(val) {
  const el = document.getElementById('ang-range');
  if (!el) return;
  const pct = (val / 355) * 100;
  el.style.background = `linear-gradient(to right,#4a90ff 0%,#4a90ff ${pct}%,rgba(74,144,255,.18) ${pct}%,rgba(74,144,255,.18) 100%)`;
}

function selAngRange(val) {
  currentAngulo = parseInt(val);
  document.getElementById('ang-deg-big').textContent = currentAngulo + 'В°';
  updateRangeTrack(currentAngulo);
  _angDrawAll();
}

// ГўвЂќв‚¬ГўвЂќв‚¬ Resize ГўвЂќв‚¬ГўвЂќв‚¬
function resizeAngCanvas() {
  const canvas = document.getElementById('ang-canvas');
  const container = document.getElementById('ang-left-panel');
  if (!canvas || !container) return;
  const size = Math.min(container.clientWidth, container.clientHeight) * 0.92;
  const dpr = window.devicePixelRatio || 1;
  canvas.width  = Math.round(size * dpr);
  canvas.height = Math.round(size * dpr);
  canvas.style.width  = size + 'px';
  canvas.style.height = size + 'px';
  canvas._cssSize = size;
}

// ГўвЂќв‚¬ГўвЂќв‚¬ Draw tudo ГўвЂќв‚¬ГўвЂќв‚¬
function _angDrawAll() {
  resizeAngCanvas();
  _drawTransferidor();
  _draw3DHose();
}

// ГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђ
//  TRANSFERIDOR CANVAS
// ГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђГўвЂўВђ
function _drawTransferidor() {
  const canvas = document.getElementById('ang-canvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  const dpr = window.devicePixelRatio || 1;
  const W = canvas._cssSize || (canvas.width / dpr);
  const H = W;
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  ctx.clearRect(0, 0, W, H);

  const cx = W / 2, cy = H / 2;
  const R  = Math.min(W, H) * 0.46;

  // Fundo branco
  ctx.beginPath(); ctx.arc(cx, cy, R * 1.08, 0, Math.PI * 2);
  ctx.fillStyle = '#fff'; ctx.fill();
  ctx.strokeStyle = '#ccc'; ctx.lineWidth = 1.5; ctx.stroke();

  // GraduaГѓВ§ГѓВЈo: 0Г‚В° = baixo (Math.PI/2), sentido horГѓВЎrio
  // ГѓвЂљngulo 0Г‚В° ГўвЂ вЂ™ bottom (ГЏв‚¬/2), 90Г‚В° ГўвЂ вЂ™ right (0), 180Г‚В° ГўвЂ вЂ™ top (-ГЏв‚¬/2), 270Г‚В° ГўвЂ вЂ™ left (ГЏв‚¬)
  // 0Г‚В°=baixo, 90Г‚В°=direita, 180Г‚В°=cima, 270Г‚В°=esquerda
  function angToRad(deg) {
    return Math.PI / 2 - deg * Math.PI / 180;
  }

  // Ticks + labels Гўв‚¬вЂќ 0Г‚В°=baixo, crescendo horГѓВЎrio pela direita
  for (let deg = 0; deg < 360; deg++) {
    const a = angToRad(deg);
    const maj10 = deg % 10 === 0;
    const maj5  = deg % 5 === 0 && !maj10;
    const tickLen = maj10 ? R * 0.10 : maj5 ? R * 0.06 : R * 0.035;
    const lw = maj10 ? 1.4 : maj5 ? 0.9 : 0.5;

    // Ponto na borda: cx + cos(a)*R, cy + sin(a)*R
    // angToRad: a = ГЏв‚¬/2 - deg*ГЏв‚¬/180
    // deg=0 ГўвЂ вЂ™ a=ГЏв‚¬/2 ГўвЂ вЂ™ cos=0, sin=1 ГўвЂ вЂ™ (cx, cy+R) = BAIXO ГўЕ“вЂњ
    // deg=90 ГўвЂ вЂ™ a=0 ГўвЂ вЂ™ cos=1, sin=0 ГўвЂ вЂ™ (cx+R, cy) = DIREITA ГўЕ“вЂњ
    const px1 = cx + Math.cos(a) * R;
    const py1 = cy + Math.sin(a) * R;   // +sin porque y cresce para baixo no canvas
    const px2 = cx + Math.cos(a) * (R - tickLen);
    const py2 = cy + Math.sin(a) * (R - tickLen);

    ctx.beginPath();
    ctx.moveTo(px1, py1);
    ctx.lineTo(px2, py2);
    ctx.strokeStyle = '#111'; ctx.lineWidth = lw; ctx.stroke();

    if (maj10) {
      const lr = R - tickLen - (deg % 30 === 0 ? 15 : 10);
      const lx = cx + Math.cos(a) * lr;
      const ly = cy + Math.sin(a) * lr;
      ctx.save();
      ctx.translate(lx, ly);
      // Rotaciona o texto para ficar tangencial ao cГѓВ­rculo, legГѓВ­vel
      // O ГѓВўngulo 'a' aponta para fora Гўв‚¬вЂќ girar texto perpendicular a isso
      ctx.rotate(a - Math.PI / 2);
      ctx.font = `${deg % 30 === 0 ? '700 12px' : '500 9px'} Inter,sans-serif`;
      ctx.fillStyle = '#111';
      ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
      ctx.fillText(deg, 0, 0);
      ctx.restore();
    }
  }

  // Arco do ГѓВўngulo atual (0Г‚В° ГўвЂ вЂ™ currentAngulo)
  if (currentAngulo !== 0) {
    const aStart = angToRad(0);
    const aEnd   = angToRad(currentAngulo);
    ctx.beginPath();
    ctx.moveTo(cx, cy);
    ctx.arc(cx, cy, R * 0.36, aStart, aEnd, false);
    ctx.closePath();
    ctx.fillStyle = 'rgba(26,86,219,0.07)'; ctx.fill();
    ctx.beginPath();
    ctx.arc(cx, cy, R * 0.36, aStart, aEnd, false);
    ctx.strokeStyle = 'rgba(26,86,219,0.25)'; ctx.lineWidth = 1.5; ctx.stroke();
  }

  // Hub central
  ctx.beginPath(); ctx.arc(cx, cy, R * 0.06, 0, Math.PI * 2);
  ctx.fillStyle = '#eee'; ctx.fill();
  ctx.strokeStyle = '#bbb'; ctx.lineWidth = 1.5; ctx.stroke();

  // ГўвЂќв‚¬ГўвЂќв‚¬ Ponteiro FIXO (0Г‚В° = baixo) Гўв‚¬вЂќ frente ГўвЂќв‚¬ГўвЂќв‚¬
  _drawPointerFixed(ctx, cx, cy, R);

  // ГўвЂќв‚¬ГўвЂќв‚¬ Ponteiro MГѓвЂњVEL (currentAngulo) Гўв‚¬вЂќ atrГѓВЎs do fixo ГўвЂќв‚¬ГўвЂќв‚¬
  _drawPointerMobile(ctx, cx, cy, R, currentAngulo);

  // Hub central sobreposto
  ctx.beginPath(); ctx.arc(cx, cy, R * 0.045, 0, Math.PI * 2);
  ctx.fillStyle = '#fff'; ctx.fill();
  ctx.strokeStyle = '#aaa'; ctx.lineWidth = 1; ctx.stroke();

  // ГўвЂќв‚¬ГўвЂќв‚¬ Drag area ГўвЂќв‚¬ГўвЂќв‚¬
  _setupAngDrag(canvas, cx, cy);
}

function _drawPointerFixed(ctx, cx, cy, R) {
  // 0Г‚В° = baixo ГўвЂ вЂ™ ГѓВўngulo canvas = -ГЏв‚¬/2 (apontando para baixo)
  // O terminal aponta para baixo com o corpo saindo para cima
  const angle = Math.PI / 2; // baixo

  if (TERMINAL_IMG.complete && TERMINAL_IMG.naturalWidth > 0) {
    const h = R * 0.48;
    const w = h * (TERMINAL_IMG.naturalWidth / TERMINAL_IMG.naturalHeight);
    ctx.save();
    ctx.translate(cx, cy);
    // Imagem aponta para cima (cabeГѓВ§a para cima) Гўв‚¬вЂќ girar 180Г‚В° para apontar para baixo (0Г‚В°)
    // mas manter no centro vertical
    // Adiciona contorno preto (sombra)
    ctx.shadowColor = '#000';
    ctx.shadowBlur = 6;
    ctx.drawImage(TERMINAL_IMG, -w / 2, -h * 0.2, w, h);
    ctx.shadowBlur = 0;
    ctx.restore();
  } else {
    _drawSimplePointer(ctx, cx, cy, Math.PI / 2, R * 0.44, '#222');
  }
}

function _drawPointerMobile(ctx, cx, cy, R, deg) {
  // angToRad: deg=0 ГўвЂ вЂ™ bottom, deg=90 ГўвЂ вЂ™ right
  const radCanvas = -(deg * Math.PI / 180); // rotaГѓВ§ГѓВЈo no canvas (sentido horГѓВЎrio visualmente)

  ctx.save();
  ctx.translate(cx, cy);
  ctx.rotate(radCanvas);

  if (TERMINAL_IMG.complete && TERMINAL_IMG.naturalWidth > 0) {
    // Mesmo layout do fixo mas colorido em azul via compositing
    const h = R * 0.48;
    const w = h * (TERMINAL_IMG.naturalWidth / TERMINAL_IMG.naturalHeight);
    // Tinge de azul
    ctx.globalAlpha = 0.85;
    // Desenha colorido: offscreen canvas com tint
    const off = document.createElement('canvas');
    off.width = w; off.height = h;
    const octx = off.getContext('2d');
    octx.drawImage(TERMINAL_IMG, 0, 0, w, h);
    octx.globalCompositeOperation = 'source-atop';
    octx.fillStyle = '#1a56db';
    octx.globalAlpha = 0.55;
    octx.fillRect(0, 0, w, h);
    ctx.shadowColor = '#000';
    ctx.shadowBlur = 6;
    ctx.drawImage(off, -w / 2, -h * 0.2, w, h);
    ctx.shadowBlur = 0;
    ctx.globalAlpha = 1;
  } else {
    // Fallback linha azul
    const len = R * 0.42;
    ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(0, len);
    ctx.strokeStyle = '#1a56db'; ctx.lineWidth = 3; ctx.lineCap = 'round'; ctx.stroke();
    ctx.beginPath(); ctx.arc(0, len, R * 0.04, 0, Math.PI * 2);
    ctx.fillStyle = '#1a56db'; ctx.fill();
  }

  ctx.restore();
}

function _drawSimplePointer(ctx, cx, cy, angle, len, color) {
  ctx.save();
  ctx.translate(cx, cy);
  ctx.rotate(angle - Math.PI / 2);
  ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(0, len);
  ctx.strokeStyle = color; ctx.lineWidth = 3; ctx.lineCap = 'round'; ctx.stroke();
  ctx.restore();
}

// ГўвЂќв‚¬ГўвЂќв‚¬ Drag para girar o ponteiro mГѓВіvel ГўвЂќв‚¬ГўвЂќв‚¬
function _setupAngDrag(canvas, cx, cy) {
  // Remove listeners antigos
  canvas.onmousedown  = null; canvas.ontouchstart = null;

  function getAngle(e) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width  / rect.width;
    const scaleY = canvas.height / rect.height;
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const clientY = e.touches ? e.touches[0].clientY : e.clientY;
    const x = (clientX - rect.left) * scaleX - cx;
    const y = (clientY - rect.top)  * scaleY - cy;
    // angToRad = ГЏв‚¬/2 - deg*ГЏв‚¬/180, entГѓВЈo deg = (ГЏв‚¬/2 - ГЋВё)*180/ГЏв‚¬
    // ГЋВё = atan2(dy, dx) onde dy = y no canvas (positivo para baixo = 0Г‚В°)
    const theta = Math.atan2(y, x);
    let deg = Math.round(((Math.PI / 2 - theta) * 180 / Math.PI + 360) % 360);
    deg = Math.round(deg / 5) * 5; // snap a cada 5Г‚В°
    return deg;
  }

  function startDrag(e) {
    _angDragging = true;
    updateFromEvent(e);
  }
  function duringDrag(e) {
    if (!_angDragging) return;
    e.preventDefault();
    updateFromEvent(e);
  }
  function endDrag() { _angDragging = false; }

  function updateFromEvent(e) {
    const deg = getAngle(e);
    currentAngulo = deg;
    document.getElementById('ang-deg-big').textContent = deg + 'В°';
    const rangeEl = document.getElementById('ang-range');
    if (rangeEl) { rangeEl.value = deg; updateRangeTrack(deg); }
    _angDrawAll();
  }

  canvas.onmousedown  = startDrag;
  canvas.ontouchstart = e => { e.preventDefault(); startDrag(e); };
  window.onmousemove  = duringDrag;
  window.ontouchmove  = e => { if (_angDragging) { e.preventDefault(); duringDrag(e); } };
  window.onmouseup    = endDrag;
  window.ontouchend   = endDrag;
  canvas.style.cursor = 'grab';
}



// IntegraГѓВ§ГѓВЈo com viewer3d
function _draw3DHose() {
  if (typeof viewer3dInit === 'function') viewer3dInit('ang-hose-3d');
}
function _resize3D() {
  if (typeof viewer3dResize === 'function') viewer3dResize();
}
function _updateHoseAngle(deg) {
  if (typeof viewer3dSetAngle === 'function') viewer3dSetAngle(deg);
}

window.addEventListener('resize', () => {
  if (document.getElementById('screen-angulos') &&
      document.getElementById('screen-angulos').classList.contains('active')) {
    _angDrawAll(); _resize3D();
  }
});

